int first(int[] values) {
  return values[0];
}

boolean contains(int[] values, int target) {
  for (int value : values) {
    if (value == target) {
      return true;
    }
  }
  return false;
}

void printPairs(int[] values) {
  for (int left : values) {
    for (int right : values) {
      System.out.println(left + "," + right);
    }
  }
}
